const CLASS_LIST = ["1年1組","1年2組","2年1組","2年2組","3年1組","3年2組","4年1組","4年2組","5年1組","5年2組","6年1組","6年2組","7年1組","7年2組","8年1組","8年2組","9年1組","9年2組"];

const formatDate = (d) => {
  const dt = new Date(d + "T00:00:00");
  return `${dt.getMonth()+1}/${dt.getDate()}`;
};

export default function App() {
  // ── State ──
  const [screen, setScreen] = useState("home");
  const [userName, setUserName] = useState("");
  const [tempName, setTempName] = useState("");
  const [selectedClass, setSelectedClass] = useState("");
  const [capturedImage, setCapturedImage] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [editAuthor, setEditAuthor] = useState("");
  const [editMemo, setEditMemo] = useState("");
  const [adminPass, setAdminPass] = useState("");
  const [adminLoggedIn, setAdminLoggedIn] = useState(false);
  const [adminFilter, setAdminFilter] = useState({ classGroup: "", dateFrom: "", dateTo: "" });
  const [records, setRecords] = useState(SAMPLE_DATA);
  const [adminTab, setAdminTab] = useState("list"); // "list" | "memo"
  const [classImages, setClassImages] = useState({}); // { "1年1組": "data:image/..." }
  const fileRef = useRef(null);
  const classImageRef = useRef(null);
  const [uploadingClass, setUploadingClass] = useState("");
  const [pastClassFilter, setPastClassFilter] = useState("");

  // ── Handlers ──
  const compressImage = (dataUrl, maxWidth = 300) => {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        const ratio = Math.min(maxWidth / img.width, maxWidth / img.height);
        canvas.width = img.width * ratio;
        canvas.height = img.height * ratio;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL("image/jpeg", 0.6));
      };
      img.src = dataUrl;
    });
  };

  const handleCapture = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      setCapturedImage(ev.target.result);
      setScreen("confirm");
    };
    reader.readAsDataURL(file);
  };

  const handleRegister = async () => {
    let thumb = null;
    if (capturedImage) {
      thumb = await compressImage(capturedImage, 200);
    }
    const newRecord = {
      id: records.length + 1,
      date: new Date().toISOString().split("T")[0],
      reader: userName,
      title: editTitle,
      author: editAuthor,
      classGroup: selectedClass,
      memo: editMemo,
      image: thumb,
    };
    setRecords([newRecord, ...records]);
    setScreen("done");
  };

  const filteredRecords = records.filter(r => {
    if (adminFilter.classGroup && r.classGroup !== adminFilter.classGroup) return false;
    if (adminFilter.dateFrom && r.date < adminFilter.dateFrom) return false;
    if (adminFilter.dateTo && r.date > adminFilter.dateTo) return false;
    return true;
  });

  const downloadCSV = () => {
    const header = "日付,学年・組,著者名,タイトル,読んだ人,子どもたちの様子メモ";
    const classOrder = (cg) => {
      const m = cg.match(/(\d+)年(\d+)組/);
      if (!m) return 9999;
      return parseInt(m[1]) * 100 + parseInt(m[2]);
    };
    const sorted = [...filteredRecords].sort((a, b) => {
      const dateCmp = a.date.localeCompare(b.date);
      if (dateCmp !== 0) return dateCmp;
      return classOrder(a.classGroup) - classOrder(b.classGroup);
    });
    const rows = sorted.map(r =>
      `${r.date},${r.classGroup},${r.author},${r.title},${r.reader},"${(r.memo || "").replace(/"/g, '""')}"`
    );
    const bom = "\uFEFF";
    const csv = bom + [header, ...rows].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `よみかたりノート_${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const resetForNextBook = () => {
    setCapturedImage(null);
    setEditTitle("");
    setEditAuthor("");
    setEditMemo("");
    setScreen("home");
  };

  const resetAll = () => {
    setCapturedImage(null);
    setEditTitle("");
    setEditAuthor("");
    setEditMemo("");
    setSelectedClass("");
    setScreen("home");
  };

  const handleClassImageUpload = (e) => {
    const file = e.target.files?.[0];
    if (!file || !uploadingClass) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      setClassImages(prev => ({ ...prev, [uploadingClass]: ev.target.result }));
      setUploadingClass("");
    };
    reader.readAsDataURL(file);
  };

  // ── Past books: grouped by class ──
  const pastBooksByClass = {};
  records.forEach(r => {
    if (!pastBooksByClass[r.classGroup]) pastBooksByClass[r.classGroup] = [];
    pastBooksByClass[r.classGroup].push(r);
  });

  // ── Styles ──
  const theme = {
    bg: "#FAFAF7",
    card: "#FFFFFF",
    accent: "#2B7A5B",
    accentLight: "#E8F5EE",
    accentDark: "#1D5A42",
    text: "#2C2C2C",
    textSub: "#7A7A7A",
    border: "#E8E8E4",
    danger: "#D94F4F",
    dangerLight: "#FFF0F0",
    warn: "#E8A317",
    warnLight: "#FFF8E8",
    radius: 12,
  };

  const s = {
    page: { minHeight: "100vh", background: theme.bg, fontFamily: "'Helvetica Neue', 'Hiragino Sans', sans-serif", color: theme.text, maxWidth: 480, margin: "0 auto", padding: "0 16px 40px" },
    header: { textAlign: "center", padding: "24px 0 8px" },
    logo: { fontSize: 22, fontWeight: 700, color: theme.accent, letterSpacing: 1 },
    subtitle: { fontSize: 12, color: theme.textSub, marginTop: 4 },
    card: { background: theme.card, borderRadius: theme.radius, padding: "20px", marginTop: 16, boxShadow: "0 1px 4px rgba(0,0,0,0.06)", border: `1px solid ${theme.border}` },
    label: { fontSize: 13, fontWeight: 600, color: theme.text, marginBottom: 6, display: "block" },
    input: { width: "100%", padding: "12px", borderRadius: 8, border: `1px solid ${theme.border}`, fontSize: 16, boxSizing: "border-box", outline: "none", background: "#FAFAF7" },
    btn: (bg, color) => ({ width: "100%", padding: "14px", borderRadius: 10, border: "none", background: bg, color: color || "#FFF", fontSize: 16, fontWeight: 600, cursor: "pointer", marginTop: 12 }),
    btnOutline: { width: "100%", padding: "14px", borderRadius: 10, border: `2px solid ${theme.accent}`, background: "transparent", color: theme.accent, fontSize: 16, fontWeight: 600, cursor: "pointer", marginTop: 12 },
    classBtn: (selected) => ({ padding: "10px 0", borderRadius: 8, border: `2px solid ${selected ? theme.accent : theme.border}`, background: selected ? theme.accentLight : "#FFF", color: selected ? theme.accentDark : theme.text, fontSize: 14, fontWeight: selected ? 600 : 400, cursor: "pointer", textAlign: "center" }),
    tag: { display: "inline-block", padding: "4px 10px", borderRadius: 6, background: theme.accentLight, color: theme.accentDark, fontSize: 12, fontWeight: 500 },
    nav: { display: "flex", gap: 8, marginTop: 16, flexWrap: "wrap", justifyContent: "center" },
    navBtn: (active) => ({ padding: "8px 16px", borderRadius: 20, border: `1.5px solid ${active ? theme.accent : theme.border}`, background: active ? theme.accentLight : "#FFF", color: active ? theme.accentDark : theme.textSub, fontSize: 13, fontWeight: active ? 600 : 400, cursor: "pointer" }),
    tabBar: { display: "flex", borderBottom: `2px solid ${theme.border}`, marginBottom: 16 },
    tab: (active) => ({ flex: 1, padding: "10px 0", textAlign: "center", fontSize: 14, fontWeight: active ? 600 : 400, color: active ? theme.accent : theme.textSub, borderBottom: active ? `2px solid ${theme.accent}` : "2px solid transparent", cursor: "pointer", background: "none", border: "none", marginBottom: -2 }),
  };

  // ══════════════════════════════════════
  // SCREENS
  // ══════════════════════════════════════

  // ── HOME ──
  if (screen === "home") {
    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>よみかたりノート</div>
          <div style={s.subtitle}>読み語りサークルの記録アプリ</div>
        </div>

        <div style={s.card}>
          <label style={s.label}>学年・組をえらんでください</label>
          <select style={s.input} value={selectedClass} onChange={e => setSelectedClass(e.target.value)}>
            <option value="">-- 選択してください --</option>
            {CLASS_LIST.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {selectedClass && (
          <div style={s.card}>
            <label style={s.label}>あなたのお名前</label>
            {userName ? (
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <span style={{ fontSize: 16, fontWeight: 500 }}>{userName}</span>
                <button onClick={() => { setUserName(""); setTempName(""); }} style={{ background: "none", border: "none", color: theme.accent, cursor: "pointer", fontSize: 13 }}>変更</button>
              </div>
            ) : (
              <div>
                <input style={s.input} placeholder="例：田中花子" value={tempName} onChange={e => setTempName(e.target.value)} />
                <button style={s.btn(theme.accent)} onClick={() => { if (tempName.trim()) setUserName(tempName.trim()); }} disabled={!tempName.trim()}>決定</button>
              </div>
            )}
          </div>
        )}

        {selectedClass && userName && (
          <div style={s.card}>
            <label style={s.label}>本の表紙を撮影してください</label>
            <p style={{ fontSize: 13, color: theme.textSub, margin: "4px 0 12px" }}>※ 一冊ずつアップロードしてください</p>
            <input ref={fileRef} type="file" accept="image/*" capture="environment" style={{ display: "none" }} onChange={handleCapture} />
            <button style={s.btn(theme.accent)} onClick={() => fileRef.current?.click()}>
              📷 表紙を撮影する
            </button>
          </div>
        )}

        {/* Bottom navigation */}
        <div style={s.nav}>
          <button style={s.navBtn(false)} onClick={() => setScreen("pastBooks")}>📚 過去の本</button>
          <button style={s.navBtn(false)} onClick={() => setScreen("adminLogin")}>🔑 管理画面</button>
        </div>
      </div>
    );
  }

  // ── CONFIRM ──
  if (screen === "confirm") {
    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>よみかたりノート</div>
        </div>
        <div style={s.card}>
          <div style={{ textAlign: "center", marginBottom: 16 }}>
            <span style={s.tag}>{selectedClass}</span>
            <span style={{ ...s.tag, marginLeft: 8, background: theme.warnLight, color: "#8B6914" }}>{userName}</span>
          </div>

          {capturedImage && (
            <div style={{ borderRadius: 8, overflow: "hidden", marginBottom: 16, border: `1px solid ${theme.border}` }}>
              <img src={capturedImage} alt="表紙" style={{ width: "100%", display: "block" }} />
            </div>
          )}

          <label style={s.label}>タイトル</label>
          <input style={s.input} value={editTitle} onChange={e => setEditTitle(e.target.value)} />

          <label style={{ ...s.label, marginTop: 12 }}>著者名</label>
          <input style={s.input} value={editAuthor} onChange={e => setEditAuthor(e.target.value)} />

          <label style={{ ...s.label, marginTop: 12 }}>子どもたちの様子メモ（任意）</label>
          <textarea
            style={{ ...s.input, minHeight: 80, resize: "vertical" }}
            placeholder="例：大盛り上がりでした！"
            value={editMemo}
            onChange={e => setEditMemo(e.target.value)}
          />

          <button style={s.btn(theme.accent)} onClick={handleRegister} disabled={!editTitle.trim()}>
            ✅ この内容で登録する
          </button>
          <button style={s.btnOutline} onClick={resetAll}>やり直す</button>
        </div>
      </div>
    );
  }

  // ── DONE ──
  if (screen === "done") {
    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>よみかたりノート</div>
        </div>
        <div style={{ ...s.card, textAlign: "center" }}>
          <div style={{ fontSize: 48, marginBottom: 8 }}>🎉</div>
          <div style={{ fontSize: 18, fontWeight: 600 }}>登録できました！</div>
          <div style={{ fontSize: 14, color: theme.textSub, marginTop: 8 }}>
            <strong>{editTitle}</strong>（{editAuthor}）
          </div>
          <div style={{ fontSize: 13, color: theme.textSub, marginTop: 4 }}>
            {selectedClass} ・ {userName}
          </div>
          {editMemo && (
            <div style={{ fontSize: 13, color: theme.accent, marginTop: 8, background: theme.accentLight, padding: "8px 12px", borderRadius: 8, textAlign: "left" }}>
              📝 {editMemo}
            </div>
          )}
          <button style={s.btn(theme.accent)} onClick={resetForNextBook}>
            📖 もう1冊登録する
          </button>
          <button style={s.btnOutline} onClick={resetAll}>トップに戻る</button>
        </div>
      </div>
    );
  }

  // ── PAST BOOKS ──
  if (screen === "pastBooks") {
    const threeYearsAgo = new Date();
    threeYearsAgo.setFullYear(threeYearsAgo.getFullYear() - 2);
    const cutoff = threeYearsAgo.toISOString().split("T")[0];
    const recentRecords = records.filter(r => r.date >= cutoff);
    const filteredPast = pastClassFilter
      ? recentRecords.filter(r => r.classGroup === pastClassFilter)
      : recentRecords;
    const sorted = [...filteredPast].sort((a, b) => b.date.localeCompare(a.date));

    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>📚 過去の本</div>
          <div style={s.subtitle}>これまでに読み語りした本の一覧</div>
          <div style={{ fontSize: 12, color: theme.warn, marginTop: 4 }}>※ 過去2年分のみ掲載</div>
        </div>

        {/* Class filter - dropdown */}
        <div style={{ marginTop: 12 }}>
          <select style={s.input} value={pastClassFilter} onChange={e => setPastClassFilter(e.target.value)}>
            <option value="">すべての学年・組</option>
            {CLASS_LIST.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {/* Books list - 2 column grid */}
        {sorted.length === 0 ? (
          <div style={{ ...s.card, textAlign: "center", color: theme.textSub }}>
            まだ記録がありません
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginTop: 12 }}>
            {sorted.map(r => (
              <div key={r.id} style={{ ...s.card, padding: "10px", marginTop: 0 }}>
                {r.image ? (
                  <img src={r.image} alt={r.title} style={{ width: "100%", aspectRatio: "3/4", objectFit: "cover", borderRadius: 6, border: `1px solid ${theme.border}`, display: "block" }} />
                ) : (
                  <div style={{ width: "100%", aspectRatio: "3/4", borderRadius: 6, background: theme.accentLight, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 32, border: `1px solid ${theme.border}` }}>📖</div>
                )}
                <div style={{ marginTop: 8 }}>
                  <div style={{ fontSize: 13, fontWeight: 600, lineHeight: 1.3, overflow: "hidden", display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical" }}>{r.title}</div>
                  <div style={{ fontSize: 11, color: theme.textSub, marginTop: 2 }}>{r.author}</div>
                  <div style={{ fontSize: 11, color: theme.textSub, marginTop: 4, display: "flex", justifyContent: "space-between" }}>
                    <span>{formatDate(r.date)}</span>
                    <span style={{ ...s.tag, fontSize: 10, padding: "2px 6px" }}>{r.classGroup}</span>
                  </div>
                  {r.memo && (
                    <div style={{ fontSize: 11, color: theme.accent, marginTop: 4, background: theme.accentLight, padding: "4px 6px", borderRadius: 4, lineHeight: 1.4, overflow: "hidden", display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical" }}>
                      📝 {r.memo}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        <button style={{ ...s.btnOutline, marginTop: 20 }} onClick={() => setScreen("home")}>
          ← トップに戻る
        </button>
      </div>
    );
  }

  // ── ADMIN LOGIN ──
  if (screen === "adminLogin") {
    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>🔑 管理画面</div>
        </div>
        <div style={s.card}>
          <label style={s.label}>合言葉を入力してください</label>
          <input style={s.input} type="password" placeholder="合言葉" value={adminPass} onChange={e => setAdminPass(e.target.value)} />
          <button style={s.btn(theme.accent)} onClick={() => {
            if (adminPass === "yomikatari") {
              setAdminLoggedIn(true);
              setScreen("admin");
            } else {
              alert("合言葉が違います");
            }
          }}>ログイン</button>
          <button style={s.btnOutline} onClick={() => { setAdminPass(""); setScreen("home"); }}>← 戻る</button>
          <p style={{ fontSize: 11, color: theme.textSub, textAlign: "center", marginTop: 12 }}>※デモ用の合言葉は「yomikatari」</p>
        </div>
      </div>
    );
  }

  // ── ADMIN ──
  if (screen === "admin") {
    return (
      <div style={s.page}>
        <div style={s.header}>
          <div style={s.logo}>📋 管理画面</div>
        </div>

        {/* Tabs */}
        <div style={s.tabBar}>
          <button style={s.tab(adminTab === "list")} onClick={() => setAdminTab("list")}>📖 登録一覧</button>
          <button style={s.tab(adminTab === "memo")} onClick={() => setAdminTab("memo")}>📝 様子メモ</button>
          <button style={s.tab(adminTab === "images")} onClick={() => setAdminTab("images")}>🖼️ クラス画像</button>
        </div>

        {/* ── LIST TAB ── */}
        {adminTab === "list" && (
          <div>
            <div style={s.card}>
              <label style={s.label}>絞り込み</label>
              <select style={{ ...s.input, marginBottom: 8 }} value={adminFilter.classGroup} onChange={e => setAdminFilter(f => ({ ...f, classGroup: e.target.value }))}>
                <option value="">すべての学年・組</option>
                {CLASS_LIST.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <div style={{ display: "flex", gap: 8 }}>
                <div style={{ flex: 1 }}>
                  <label style={{ fontSize: 12, color: theme.textSub }}>開始日</label>
                  <input type="date" style={s.input} value={adminFilter.dateFrom} onChange={e => setAdminFilter(f => ({ ...f, dateFrom: e.target.value }))} />
                </div>
                <div style={{ flex: 1 }}>
                  <label style={{ fontSize: 12, color: theme.textSub }}>終了日</label>
                  <input type="date" style={s.input} value={adminFilter.dateTo} onChange={e => setAdminFilter(f => ({ ...f, dateTo: e.target.value }))} />
                </div>
              </div>
              <button style={{ ...s.btn("transparent", theme.textSub), fontSize: 13, marginTop: 8, textDecoration: "underline", padding: 4 }} onClick={() => setAdminFilter({ classGroup: "", dateFrom: "", dateTo: "" })}>
                フィルタをリセット
              </button>
            </div>

            <div style={{ ...s.card, padding: "12px 16px" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
                <span style={{ fontSize: 14, fontWeight: 600 }}>{filteredRecords.length}件</span>
                <button onClick={downloadCSV} style={{ background: theme.accent, color: "#FFF", border: "none", borderRadius: 8, padding: "8px 16px", fontSize: 13, fontWeight: 500, cursor: "pointer" }}>
                  📥 CSVダウンロード
                </button>
              </div>

              {filteredRecords.sort((a, b) => b.date.localeCompare(a.date)).map(r => (
                <div key={r.id} style={{ padding: "10px 0", borderBottom: `1px solid ${theme.border}` }}>
                  <div style={{ display: "flex", justifyContent: "space-between" }}>
                    <div>
                      <span style={{ fontSize: 14, fontWeight: 500 }}>{r.title}</span>
                      <span style={{ fontSize: 12, color: theme.textSub, marginLeft: 6 }}>{r.author}</span>
                    </div>
                    <span style={{ ...s.tag, fontSize: 11 }}>{r.classGroup}</span>
                  </div>
                  <div style={{ fontSize: 12, color: theme.textSub, marginTop: 4 }}>
                    {formatDate(r.date)} ・ {r.reader}
                  </div>
                  {r.memo && (
                    <div style={{ fontSize: 12, color: theme.accent, marginTop: 4 }}>📝 {r.memo}</div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ── MEMO TAB ── */}
        {adminTab === "memo" && (
          <div>
            <div style={{ ...s.card, background: theme.warnLight, border: `1px solid #E8D5A0` }}>
              <div style={{ fontSize: 13, color: "#8B6914" }}>
                💡 保護者が登録時に入力した「子どもたちの様子メモ」をまとめて確認できます。メモ付きの記録のみ表示しています。
              </div>
            </div>
            {records.filter(r => r.memo).sort((a, b) => b.date.localeCompare(a.date)).map(r => (
              <div key={r.id} style={s.card}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                  <div>
                    <div style={{ fontSize: 15, fontWeight: 600 }}>{r.title}</div>
                    <div style={{ fontSize: 13, color: theme.textSub }}>{r.author}</div>
                  </div>
                  <span style={s.tag}>{r.classGroup}</span>
                </div>
                <div style={{ fontSize: 12, color: theme.textSub, marginTop: 6 }}>
                  📅 {formatDate(r.date)} ・ 👤 {r.reader}
                </div>
                <div style={{ fontSize: 14, color: theme.text, marginTop: 10, background: theme.accentLight, padding: "10px 14px", borderRadius: 8, lineHeight: 1.6 }}>
                  📝 {r.memo}
                </div>
              </div>
            ))}
            {records.filter(r => r.memo).length === 0 && (
              <div style={{ ...s.card, textAlign: "center", color: theme.textSub }}>
                メモ付きの記録はまだありません
              </div>
            )}
          </div>
        )}

        {/* ── IMAGES TAB ── */}
        {adminTab === "images" && (
          <div>
            <div style={{ ...s.card, background: theme.accentLight, border: `1px solid #B5D9C8` }}>
              <div style={{ fontSize: 13, color: theme.accentDark }}>
                🖼️ 各クラスの画像をアップロードできます。読み語りの様子や集合写真などを記録に残しましょう。
              </div>
            </div>
            <input ref={classImageRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleClassImageUpload} />
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginTop: 12 }}>
              {CLASS_LIST.map(c => (
                <div key={c} style={{ ...s.card, padding: "12px", textAlign: "center" }}>
                  <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 8 }}>{c}</div>
                  {classImages[c] ? (
                    <div>
                      <img src={classImages[c]} alt={c} style={{ width: "100%", borderRadius: 8, marginBottom: 8 }} />
                      <button style={{ background: theme.dangerLight, color: theme.danger, border: "none", borderRadius: 6, padding: "6px 12px", fontSize: 12, cursor: "pointer" }} onClick={() => {
                        setClassImages(prev => { const n = { ...prev }; delete n[c]; return n; });
                      }}>削除</button>
                    </div>
                  ) : (
                    <button style={{ background: theme.accentLight, color: theme.accentDark, border: `1px dashed ${theme.accent}`, borderRadius: 8, padding: "20px 12px", fontSize: 13, cursor: "pointer", width: "100%" }} onClick={() => {
                      setUploadingClass(c);
                      setTimeout(() => classImageRef.current?.click(), 100);
                    }}>
                      📷 画像を追加
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        <button style={{ ...s.btnOutline, marginTop: 20 }} onClick={() => { setAdminLoggedIn(false); setAdminPass(""); setAdminTab("list"); setScreen("home"); }}>
          ← トップに戻る
        </button>
      </div>
    );
  }

  return null;
}
